 11	  Accordion,
 12	  AccordionContent,
 13	  AccordionItem,
 14	  AccordionToggle,
 15	  Card,
 16	  CardHeader,
 17	  CardTitle,
 18	  Divider,
 19	  Grid,
 20	  Label,
 21	} from '@patternfly/react-core';
 22	
 23	import { ERROR } from './utils/constants';
 24	import { getVMStatuses } from './utils/utils';
 25	import VMStatusItem from './VMStatusItem';
 26	
 27	import './VMStatusesCard.scss';
 28	
 29	const VMStatusesCard: React.FC = () => {
 30	  const [activeNamespace] = useActiveNamespace();
 31	  const namespace = React.useMemo(
 32	    () => (activeNamespace === ALL_NAMESPACES_SESSION_KEY ? null : activeNamespace),
 33	    [activeNamespace],
 34	  );
 35	
 36	  const { t } = useKubevirtTranslation();
 37	  const [vms] = useK8sWatchResource<V1VirtualMachine[]>({
 38	    groupVersionKind: VirtualMachineModelGroupVersionKind,
 39	    isList: true,
 40	    namespace: namespace,
 41	    namespaced: Boolean(namespace),
 42	  });
 43	  const [showExtraStatuses, setShowExtraStatuses] = React.useState<boolean>(false);
 44	
 45	  const { additionalStatuses, primaryStatuses } = getVMStatuses(vms || []);
 46	
 47	  return (
 48	    <Card className="vm-statuses-card" data-test-id="vm-statuses-card">
 49	      <CardHeader className="vm-statuses-card__header">
 50	        <CardTitle>{t('VirtualMachine statuses')}</CardTitle>
 51	      </CardHeader>
 52	      <div className="vm-statuses-card__body">
 53	        <Grid hasGutter>
 54	          <VMStatusItem count={primaryStatuses.Error} namespace={activeNamespace} status={ERROR} />
 55	          <VMStatusItem
 56	            count={primaryStatuses.Running}
 57	            namespace={activeNamespace}
 58	            status={VM_STATUS.Running}
 59	          />
 60	          <VMStatusItem
 61	            count={primaryStatuses.Stopped}
 62	            namespace={activeNamespace}
 63	            status={VM_STATUS.Stopped}
 64	          />
 65	          <VMStatusItem
 66	            count={primaryStatuses.Paused}
 67	            namespace={activeNamespace}
 68	            status={VM_STATUS.Paused}
 69	          />
 70	        </Grid>
 71	      </div>
 72	      <Divider />
 73	      <div className="vm-statuses-card__accordion">
 74	        <Accordion>
 75	          <AccordionItem>
 76	            <AccordionToggle
 77	              className="vm-statuses-card__accordion-toggle"
 78	              id="status-accordion-toggle"
 79	
 80	              onClick={() => setShowExtraStatuses(!showExtraStatuses)}
 81	            >
 82	              <span className="vm-statuses-card__accordion-toggle--text">
 83	                {t('Additional statuses')}
 84	              </span>
 85	              <Label
 86	                className="vm-statuses-card__accordion-toggle--label"
 87	                isCompact
 88	                key="vm-status-accordion-toggle-label"
 89	              >
 90	                {Object.keys(additionalStatuses).length}
 91	              </Label>
 92	            </AccordionToggle>
 93	            <Divider />
 94	            <AccordionContent
 95	              className="vm-statuses-card__accordion-content"
 96	              id="status-accordion-content"
 97	
 98	            >
 99	              <Grid hasGutter>
100	                {Object.keys(additionalStatuses)?.map((state) => {
101	                  const count = additionalStatuses?.[state];
102	                  return (
103	                    <VMStatusItem
104	                      count={count}
105	                      key={state}
106	                      namespace={activeNamespace}
107	                      status={state}
108	                    />
109	                  );
110	                })}
111	              </Grid>
112	            </AccordionContent>
113	          </AccordionItem>
114	        </Accordion>
115	      </div>
116	    </Card>
117	  );
118	};
119	
120	export default VMStatusesCard;

